import { DictionaryArray, BeepBoxOption, InstrumentType, toNameMap, TypePresets } from "../synth/SynthConfig";

export interface PresetCategory extends BeepBoxOption {
    readonly presets: DictionaryArray<Preset>;
}

export interface Preset extends BeepBoxOption {
    readonly isNoise?: boolean;
    readonly isMod?: boolean;
    readonly generalMidi?: boolean;
    readonly midiProgram?: number;
    readonly midiSubharmonicOctaves?: number;
    readonly customType?: InstrumentType;
    readonly settings?: any;

    readonly tags?: any;
    readonly id?: any;
}

export const fullTagList: string[] = [
    "chip", "chipwave", "customchip", "fm", "fm4op", "fm6op", "pwm", "supersaw", "pickedstring", "harmonics", "spectrum", "noise", "drumset"

    , "featured", "novelty"

    , "retro", "keys", "idiophone", "guitar", "picked", "distortion", "bellows", "string", "vocal", "brass", "reed", "flute", "pad"
    , "drums", "kick", "snare", "hihat"
    , "ambience", "chiptune", "dubstep", "bass", "lead", "sfx"

    , "cooltasdude", "dx7fm", "honeykitkd", "calamity", "thatbeepboxguy", "truemori", "thetunecrusher", "bagel", "ia.kisha", "snowirei", "krmailence", "damagelol",
     "spendog", "somethingoriginal", "eggfry", "august", "treethletress", "synthetic", "sup3r", "rblx_inst", "jayden256", "3001ideaz", "ex1",
    "ashiiware", "jacobar475", "formskooooo", "dragoncoder047"
    
    , "beepbox", "jummbox", "ultrabox", "sandbox", "midbox", "abyssbox", "awesomebox",  "bulbbox", "slarmoo'sbox", "unbox", "41box"
];

export const isMobile: boolean = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini|android|ipad|playbook|silk/i.test(navigator.userAgent);

export function prettyNumber(value: number): string {
    return value.toFixed(2).replace(/\.?0*$/, "");
}

